import React, { useEffect, useState } from 'react';
import AdminLayout from '../../components/AdminLayout';
import { adminAPI } from '../../services/api';

const Users = () => {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');

  useEffect(() => {
    fetchUsers();
  }, []);

  // ✅ LOAD USERS
  const fetchUsers = async () => {
    setLoading(true);
    try {
      const res = await adminAPI.getUsers();

      const data = res.data.users || res.data;
      setUsers(data);
    } catch (err) {
      console.error("GET USERS ERROR:", err);
      setUsers([]);
    } finally {
      setLoading(false);
    }
  };

  // ✅ TOGGLE ACTIVE USER
  const toggleActive = async (user) => {
    try {
      await adminAPI.updateUser(user._id, {
        isActive: !user.isActive,
      });

      setUsers(prev =>
        prev.map(u =>
          u._id === user._id
            ? { ...u, isActive: !u.isActive }
            : u
        )
      );
    } catch (err) {
      console.error("TOGGLE ERROR:", err);
    }
  };

  // ✅ SEARCH (frontend)
  const handleSearch = (e) => {
    e.preventDefault();

    const filtered = users.filter(u =>
      u.fullName?.toLowerCase().includes(search.toLowerCase()) ||
      u.email?.toLowerCase().includes(search.toLowerCase())
    );

    setUsers(filtered);
  };

  return (
    <AdminLayout title="Users">

      {/* SEARCH */}
      <form onSubmit={handleSearch} style={styles.searchBar}>
        <input
          style={styles.searchInput}
          placeholder="Search by name or email..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
        <button type="submit" style={styles.searchBtn}>
          Search
        </button>
      </form>

      {/* TABLE */}
      <div style={styles.card}>
        {loading ? (
          <div style={styles.loading}>Loading...</div>
        ) : (
          <table style={styles.table}>
            <thead>
              <tr>
                {['User', 'Phone', 'Role', 'Joined', 'Status', 'Action'].map(h => (
                  <th key={h} style={styles.th}>{h}</th>
                ))}
              </tr>
            </thead>

            <tbody>
              {users.map(user => (
                <tr key={user._id}>
                  <td style={styles.td}>
                    <div style={styles.userCell}>
                      <div style={styles.avatar}>
                        {user.fullName?.[0]?.toUpperCase()}
                      </div>
                      <div>
                        <div style={{ fontSize: '13px', fontWeight: '500' }}>
                          {user.fullName}
                        </div>
                        <div style={{ fontSize: '11px', color: '#888780' }}>
                          {user.email}
                        </div>
                      </div>
                    </div>
                  </td>

                  <td style={styles.td}>{user.phone}</td>

                  <td style={styles.td}>
                    <span style={{
                      ...styles.badge,
                      background: user.role === 'admin' ? '#E6F1FB' : '#F8F6F2',
                      color: user.role === 'admin' ? '#185FA5' : '#888780'
                    }}>
                      {user.role}
                    </span>
                  </td>

                  <td style={styles.td}>
                    {user.createdAt
                      ? new Date(user.createdAt).toLocaleDateString()
                      : '-'}
                  </td>

                  <td style={styles.td}>
                    <span style={{
                      ...styles.badge,
                      background: user.isActive ? '#EAF3DE' : '#FCEBEB',
                      color: user.isActive ? '#3B6D11' : '#A32D2D'
                    }}>
                      {user.isActive ? 'Active' : 'Inactive'}
                    </span>
                  </td>

                  <td style={styles.td}>
                    <button
                      style={{
                        ...styles.actionBtn,
                        background: user.isActive ? '#FCEBEB' : '#EAF3DE',
                        color: user.isActive ? '#A32D2D' : '#3B6D11'
                      }}
                      onClick={() => toggleActive(user)}
                    >
                      {user.isActive ? 'Deactivate' : 'Activate'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </AdminLayout>
  );
};

export default Users;
